#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define PI 3.1415926535897932
#define M 2147483647
#define A 1103515245
#define C 12345

double roundDouble(double value) {
    int newValue = (int)(value);
    if (value - newValue < 0.5)
        return (double)newValue;
    else
        return (double)(newValue + 1);
}

double randu(int * seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs((double)seed[index] / (double)M);
}

double randn(int * seed, int index) {
    double u = randu(seed, index);
    double v = randu(seed, index);
    double cosine = cos(2.0 * PI * v);
    double rt = -2.0 * log(u);
    return sqrt(rt) * cosine;
}

void likelihood_kernel(
    global double * arrayX,
    global double * arrayY,
    global double * xj,
    global double * yj,
    global double * CDF,
    global int * ind,
    global int * objxy,
    global double * likelihood,
    global unsigned char * I,
    global double * u,
    global double * weights,
    int Nparticles,
    int countOnes,
    int max_size,
    int k,
    int IszY,
    int Nfr,
    global int * seed,
    global double * partial_sums,
    local double * local_sum
) {
    int x = get_global_id(0);
    int local_id = get_local_id(0);

    if (x < Nparticles) {
        arrayX[x] += 1.0 + 5.0 * randn(seed, x);
        arrayY[x] += -2.0 + 2.0 * randn(seed, x);

        double lik = 0.0;
        for (int y = 0; y < countOnes; y++) {
            int indX = (int)roundDouble(arrayX[x]) + objxy[y * 2 + 1];
            int indY = (int)roundDouble(arrayY[x]) + objxy[y * 2];
            int idx = abs(indX * IszY * Nfr + indY * Nfr + k);
            if (idx >= max_size) idx = 0;

            int val = I[idx];
            lik += ((pow((double)(val - 100), 2.0) - pow((double)(val - 228), 2.0)) / 50.0);
        }
        likelihood[x] = lik / (double)countOnes;
        weights[x] = weights[x] * exp(likelihood[x]);

        local_sum[local_id] = weights[x];
    } else {
        local_sum[local_id] = 0.0;
    }

    for (int s = get_local_size(0) / 2; s > 0; s >>= 1) {
        if (local_id < s) {
            local_sum[local_id] += local_sum[local_id + s];
        }
    }

    if (local_id == 0) {
        partial_sums[get_group_id(0)] = local_sum[0];
    }
}

void sum_kernel(
    global double * partial_sums,
    int Nparticles
) {
    int x = get_global_id(0);
    if (x == 0) {
        double total = 0.0;
        int num_blocks = (Nparticles + get_local_size(0) - 1) / get_local_size(0);
        for (int i = 0; i < num_blocks; i++) {
            total += partial_sums[i];
        }
        partial_sums[0] = total;
    }
}

void normalize_weights_kernel(
    global double * weights,
    int Nparticles,
    global double * partial_sums,
    global double * CDF,
    global double * u,
    global int * seed
) {
    int x = get_global_id(0);
    if (x < Nparticles) {
        double sumWeights = partial_sums[0];
        weights[x] = weights[x] / sumWeights;

        if (x == 0) {
            CDF[0] = weights[0];
        } else {
            CDF[x] = weights[x] + CDF[x-1];
        }

        if (x == 0) {
            double u1 = (1.0 / (double)Nparticles) * randu(seed, 0);
            for (int i = 0; i < Nparticles; i++) {
                u[i] = u1 + (double)i / (double)Nparticles;
            }
        }
    }
}

void find_index_kernel(
    global double * arrayX,
    global double * arrayY,
    global double * CDF,
    global double * u,
    global double * xj,
    global double * yj,
    global double * weights,
    int Nparticles
) {
    int j = get_global_id(0);
    if (j < Nparticles) {
        double value = u[j];
        int index = -1;

        int low = 0, high = Nparticles - 1;
        while (low <= high) {
            int mid = (low + high) / 2;
            if (CDF[mid] >= value) {
                index = mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }

        if (index == -1) index = Nparticles - 1;

        xj[j] = arrayX[index];
        yj[j] = arrayY[index];

        arrayX[j] = xj[j];
        arrayY[j] = yj[j];
        weights[j] = 1.0 / (double)Nparticles;
    }
}

